/* WP SMS Chatbox – Modern JS */
(function () {
  'use strict';

  function setChatBoxHeight() {
    var el = document.querySelector('.wpsms-chatbox__elements');
    if (!el) return;
    var vh = window.innerHeight || document.documentElement.clientHeight || document.body.clientHeight;
    var vw = window.innerWidth || document.documentElement.clientWidth || document.body.clientWidth;
    el.style.maxHeight = (vw >= 768 ? 0.65 : 0.54) * vh + 'px';
  }

  document.addEventListener('DOMContentLoaded', function () {
    /* ---- Dark mode detection ---- */
    var root = document.documentElement;
    if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
      root.classList.add('dark-theme');
      root.classList.remove('light-theme');
    } else {
      root.classList.remove('dark-theme');
      root.classList.add('light-theme');
    }

    /* ---- Element refs ---- */
    var content = document.querySelector('.wpsms-chatbox__content');
    var toggleBtn = document.querySelector('.js-wpsms-chatbox__button');
    var closeBtn = document.querySelector('.js-wpsms-chatbox__close-button');
    var backdrop = document.querySelector('.js-wpsms-chatbox__backdrop');

    if (!content || !toggleBtn) return;

    /* ---- Reduced motion check ---- */
    var prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    /* ---- Open / Close helpers ---- */
    function openPanel() {
      content.style.display = 'block';
      /* Force reflow before adding animation classes */
      content.offsetHeight; // eslint-disable-line no-unused-expressions
      content.classList.add('open', 'opening');
      document.body.classList.add('chatbox-open');
      toggleBtn.setAttribute('aria-expanded', 'true');

      if (backdrop) {
        backdrop.classList.add('active');
      }

      /* Move focus to close button for accessibility */
      if (closeBtn) {
        setTimeout(function () { closeBtn.focus(); }, prefersReducedMotion ? 0 : 300);
      }
    }

    function closePanel() {
      content.classList.remove('open');
      content.classList.add('closing');
      document.body.classList.remove('chatbox-open');
      toggleBtn.setAttribute('aria-expanded', 'false');

      if (backdrop) {
        backdrop.classList.remove('active');
      }

      /* Fallback: if reduced motion or no animation class, hide immediately */
      if (prefersReducedMotion || (!content.classList.contains('wpsms-chatbox__content--fade') && !content.classList.contains('wpsms-chatbox__content--slide'))) {
        hidePanelAfterAnimation();
      }
    }

    function hidePanelAfterAnimation() {
      content.style.display = 'none';
      content.classList.remove('opening', 'closing');
    }

    /* ---- Toggle button click ---- */
    toggleBtn.addEventListener('click', function () {
      if (content.classList.contains('open')) {
        closePanel();
      } else {
        openPanel();
      }
    });

    /* ---- Close button click ---- */
    if (closeBtn) {
      closeBtn.addEventListener('click', function () {
        closePanel();
      });
    }

    /* ---- Backdrop click (mobile) ---- */
    if (backdrop) {
      backdrop.addEventListener('click', function () {
        closePanel();
      });
    }

    /* ---- Click outside to close ---- */
    document.addEventListener('click', function (e) {
      if (!content.classList.contains('open')) return;
      var chatbox = document.querySelector('.wpsms-chatbox');
      if (chatbox && !chatbox.contains(e.target)) {
        closePanel();
      }
    });

    /* ---- Keyboard: Escape to close ---- */
    document.addEventListener('keydown', function (e) {
      if (e.key === 'Escape' && content.classList.contains('open')) {
        closePanel();
        toggleBtn.focus();
      }
    });

    /* ---- Focus trap within panel ---- */
    content.addEventListener('keydown', function (e) {
      if (e.key !== 'Tab') return;

      var focusable = content.querySelectorAll(
        'a[href], button:not([disabled]), input:not([disabled]), textarea:not([disabled]), select:not([disabled]), [tabindex]:not([tabindex="-1"])'
      );
      if (focusable.length === 0) return;

      var first = focusable[0];
      var last = focusable[focusable.length - 1];

      if (e.shiftKey) {
        if (document.activeElement === first) {
          e.preventDefault();
          last.focus();
        }
      } else {
        if (document.activeElement === last) {
          e.preventDefault();
          first.focus();
        }
      }
    });

    /* ---- Handle animation end ---- */
    content.addEventListener('animationend', function () {
      if (content.classList.contains('closing')) {
        hidePanelAfterAnimation();
      }
      content.classList.remove('opening', 'closing');
    });

    /* Fallback: transition end for non-animated mode */
    content.addEventListener('transitionend', function (e) {
      if (e.propertyName !== 'opacity') return;
      if (!content.classList.contains('open')) {
        hidePanelAfterAnimation();
      }
    });

    /* ---- Initial height calc ---- */
    setChatBoxHeight();
  });

  window.addEventListener('resize', setChatBoxHeight);
})();
